function mention(moyenne) {
  if (moyenne < 10) return 'Ajourné';
  else if (moyenne < 12) return 'Passable';
  else if (moyenne < 14) return 'Assez Bien';
  else if (moyenne < 16) return 'Bien';
  else return 'Très Bien';
}

// Tests
console.log(mention(9.5)); // Ajourné
console.log(mention(11));  // Passable
console.log(mention(13.8));// Assez Bien
console.log(mention(15.2));// Bien
console.log(mention(17));  // Très Bien
```

