```

```javascript
function orientation(notes) {
  // Série C
  if (notes.maths >= 12 && notes.pc >= 12) {
    return 'C';
  } 
  // Série D
  else if (notes.svt >= 14 && (notes.maths >= 10 || notes.pc >= 10)) {
    return 'D';
  }
  // Série A
  else if (notes.francais >= 14 && notes.anglais >= 12) {
    return 'A';
  }
  // Série E (par défaut)
  else {
    return 'E';
  }
}

// Test
let eleve = { maths: 11, pc: 13, svt: 15, francais: 10, anglais: 9 };
console.log(orientation(eleve)); // D
```
